@dataclass
class ModelLocation:
    bucket: str
    prefix: str


def parse_s3_uri(uri: str) -> ModelLocation:
    parsed = urlparse(uri)
    if parsed.scheme != "s3" or not parsed.netloc:
        raise ValueError("MODEL_PATH must be a valid s3://bucket/prefix URI")
    prefix = parsed.path.lstrip("/")
    return ModelLocation(bucket=parsed.netloc, prefix=prefix.rstrip("/"))


def extract_version(key: str) -> Tuple[int, ...]:
    matches = re.findall(r"\d+", key)
    if not matches:
        return (0,)
    return tuple(int(x) for x in matches)


def find_latest_model_object(s3_client, location: ModelLocation) -> Optional[str]:
    paginator = s3_client.get_paginator("list_objects_v2")
    latest_key = None
    latest_version = None
    latest_mtime = None

    for page in paginator.paginate(Bucket=location.bucket, Prefix=location.prefix):
        for obj in page.get("Contents", []):
            key = obj["Key"]
            if key.endswith("/") or not (
                key.endswith(".pkl") or key.endswith(".pickle") or key.endswith(".joblib")
            ):
                continue

            version = extract_version(key)
            mtime = obj["LastModified"]

            if latest_key is None:
                latest_key = key
                latest_version = version
                latest_mtime = mtime
                continue

